const aiText = $input.first().json.content.parts[0].text;
const parsed = JSON.parse(aiText);

const airtableRecord = $('Search records').first().json;

return [
  {
    json: {
      record_id: airtableRecord.id,
      nombre: airtableRecord.fields.Nombre,
      email: airtableRecord.fields.Email,
      asunto: airtableRecord.fields.Asunto,
      mensaje: airtableRecord.fields.Mensaje,
      ...parsed
    }
  }
];

